INSERT INTO `ItemMaster` VALUES (9478,'G. Power',1,10,1,0,0,0,0,0,0,0,0,'@Strengthens Sauro G2 weapons.@*Strengthens the equipped one.@*Strengthening may fail.','" getequipid 2; check VAL0==4649,L_L,-; check VAL0==5599,L_L,-; check VAL0==5773,L_L,-; check VAL0==6606,L_L,-; check VAL0==6759,L_L,-; additem 9478,1; mes "#L 208,The item to be strengthened is wrong."; end; L_L: random VAL0,100; check VAL0>=75,-,L_M; random VAL20,6; set VAL20 += 5; getequipid 2; check VAL0==4649,L_B,-; check VAL0==5599,L_S,-; check VAL0==5773,L_F,-; check VAL0==6606,L_R,-; check VAL0==6759,L_T,-; L_M: mes "#L 208,Failed to strengthen."; end; L_B: changeequip 2,4663,0; equipidAddStatus 0,2,VAL20,0,0; mes "#L 213,Sauro Blade G2 was strengthened."; end; L_S: changeequip 2,5611,0; equipidAddStatus 0,2,VAL20,0,0; mes "#L 213,Sauro Shooter G2 was strengthened."; end; L_F: changeequip 2,5783,0; equipidAddStatus 0,2,VAL20,0,0; mes "#L 213,Sauro Fang G2 was strengthened."; end; L_R: changeequip 2,6616,0; equipidAddStatus 0,2,VAL20,0,0; mes "#L 213,Sauro Stick G2 was strengthened."; end; L_T: changeequip 2,6770,0; equipidAddStatus 0,2,VAL20,0,0; mes "#L 213,Sauro Aster G2 was strengthened."; end; "');
INSERT INTO `ItemMaster` VALUES (9479,'Alris Ticket',1,10,1,0,0,0,0,0,0,0,2097160,'@Strengthens Alris weapons.@*Strengthens the equipped one.','" getequipid 2; check VAL0==4993,L_L,-; check VAL0==5998,L_L,-; check VAL0==5898,L_L,-; check VAL0==6997,L_L,-; check VAL0==6898,L_L,-; additem 9479,1; mes "#L 208,The item to be strengthened is wrong."; end; L_L: getequipid 2; check VAL0==4993,L_B,-; check VAL0==5998,L_S,-; check VAL0==5898,L_F,-; check VAL0==6997,L_R,-; check VAL0==6898,L_T,-; L_B: changeequip 2,4987,0; equipidAddStatus 0,2,52,0,0; mes "#L 213,Alris Sword was strengthened."; end; L_S: changeequip 2,5995,0; equipidAddStatus 0,2,57,0,0; mes "#L 213,Alris Bow was strengthened."; end; L_F: changeequip 2,5895,0; equipidAddStatus 0,2,58,0,0; mes "#L 213,Alris Claw was strengthened."; end; L_R: changeequip 2,6991,0; equipidAddStatus 0,2,50,0,0; mes "#L 213,Alris Rod was strengthened."; end; L_T: changeequip 2,6895,0; equipidAddStatus 0,2,50,0,0; mes "#L 213,Alris Knife was strengthened."; end; "');
