INSERT INTO `ItemMaster` VALUES (9483,'Hydrangea Candle',0,10,1,0,0,0,0,0,0,0,8,'@HP heal amount depends on Lv.@Heal amount up in June','" set VAL20 = mLv; set VAL20 *= 4; set VAL0 = mVit; set VAL0 *= 6; set VAL20 += VAL0; set VAL0 = mLv; set VAL0 *= mVit; set VAL0 *= 2; set VAL0 /= 10; set VAL20 += VAL0; set VAL20 /= 10; check VAL20<1,-,L_E; set VAL20 = 1; L_E: gettime 6; check VAL0==5,-,L_N; set VAL20 += 500; L_N: itemheal VAL20,0; end; "');
