INSERT INTO `ItemMaster` VALUES (9491,'Miracle Seed',0,10,1,0,0,0,0,0,0,0,0,'@Nobody knows what''s gonna happen!@Just try it and you''ll see!','" random VAL20,100; check VAL20<1,-,L_N1; sc_start 0,0,0; end; L_N1: check VAL20<5,-,L_N2; itemheal MaxHp,0; end; L_N2: check VAL20<10,-,L_N3; itemheal 0,MaxSp; end; L_N3: check VAL20<30,-,L_N4; itemheal 1000,1000; end; L_N4: check VAL20<60,-,L_N5; sc_start 1,100,7777; sc_start 2,100,0; sc_start 4,100,0; sc_start 5,100,0; sc_start 6,100,0; check DeviceFlag==0,L_E,-; sc_start 7,100,0; sc_start 8,100,0; sc_start 9,100,0; sc_start 10,100,0; end; L_N5: itemheal 500,500; L_E: end; "');
