INSERT INTO `ItemMaster` VALUES (14375,'Daredevil''s Bracelet',52,100000,10000,0,0,0,0,0,0,0,0,'@Movement speed+10% with Swords&@Claws. DEX&Accuracy rate&Critical@rate greatly decreases.@Great ATK up by Lv','" check WeaponType==1,L_A,-; check WeaponType==4,L_A,-; end; L_A: set bMSpd = 10; set VAL0 = mLv; set VAL0 += 100; check VAL0>550,-,L_N; set VAL0 = 550; L_N: set bAtk = VAL0; setPercent VAL20,-VAL0,1; set bAtkRate = VAL20; set bDex = -70; set bHitRate = -70; set bFixHit = -70; set bCriticalRate = -45; end; "');
INSERT INTO `ItemMaster` VALUES (14376,'Headless Bird Ring',52,1000,100,0,0,0,0,0,0,0,0,'@Auto MP recovery-110% Fear+0.1%@Paralyze+0.5% KO+0.1%','" set bSPrecovRate = -110; set bTerrRate = 1; set bPrizRate = 5; set bStanRate = 1; end; "');
INSERT INTO `ItemMaster` VALUES (14377,'Crystal Piece Choker',52,10,1,0,0,0,0,0,0,0,0,'@Spell burst+10% Delay-1 sec@Magic pierce+5% Ailment R+20%','" set bMagCritical = 10; set bItemDT = -10; set bSkillDT = -10; set bMobMDefCutRate = 5; set bPhysical = 20; end; "');
INSERT INTO `ItemMaster` VALUES (14378,'Hotstone Brooch',52,10,1,0,0,0,0,0,0,0,0,'@Freeze time-50%, All stats+5','" set bFrozenTimeRateFromEnemy = 50; set bStr=5; set bAgi=5; set bVit=5; set bInt=5; set bDex=5; set bLuk=5; end; "');
INSERT INTO `ItemMaster` VALUES (14379,'Santa Strap',52,10,1,0,0,0,0,0,0,0,0,'@MaxHP+2000 @Filled with Piton''s gratitude','" set bMaxHP = 2000; end; "');
