INSERT INTO `ItemMaster` VALUES (14381,'Rose Necklace',52,100000,10000,0,0,0,0,0,0,0,0,'@ATK+1%, Reflect+7%@Recoil+2%, All damage cut-15%@ATK up based on AGI','"  set bAtkRate = 1; set bReflection = 7; set bSutemiRate = 2; set bAllGuard = -15; set VAL0 = mAgi; set bAtk = VAL0; end; "');
