


DROP TABLE IF EXISTS `ItemMaster`;
CREATE TABLE `ItemMaster` (
  `ItemID` int NOT NULL,
  `Name` varchar(30) NOT NULL,
  `Type` int NOT NULL,
  `BuyPrice` int NOT NULL,
  `SellPrice` int NOT NULL,
  `Attack` int NOT NULL,
  `Defence` int NOT NULL,
  `Range` int NOT NULL,
  `Slot` int NOT NULL,
  `Level` int NOT NULL,
  `Model` int NOT NULL,
  `Texture` int NOT NULL,
  `Mode` int NOT NULL,
  `Comment` varchar(250) NOT NULL,
  `Script` varchar(2048) NOT NULL,
  PRIMARY KEY (`ItemID`)
);

